const GRID_SIZE = 40;
const SCREEN_WIDTH = 800;
const SCREEN_HEIGHT = 600;
const START_X = 400;
const START_Y = 550;
const GOAL_Y = 20;
const CAR_COLLISION_THRESHOLD = 30;
const LOG_COLLISION_THRESHOLD = 35;
const LOG_WIDTH = 80;

// Game state (persistent across frames)
if (!state) {
  state = {
    frogX: START_X,
    frogY: START_Y,
    inWater: false,
    onLog: false,
    logId: -1,
    gameActive: true
  };
}

// Car lane Y positions (top to bottom)
const CAR_LANES = [80, 120, 160, 200, 240, 280];
// Water lane Y positions
const WATER_LANES = [320, 360, 400, 440, 480];

// Get frog sprite
const frog = input.entity_0_in;
if (!frog) {
  output.data_out = { error: "No frog sprite connected" };
  return;
}

// Get input actions
const actions = input.data_0_in || {};

// Handle frog movement (40px grid steps)
let newX = state.frogX;
let newY = state.frogY;

if (actions.up) {
  newY = Math.max(newY - GRID_SIZE, 0);
}
if (actions.down) {
  newY = Math.min(newY + GRID_SIZE, SCREEN_HEIGHT - GRID_SIZE);
}
if (actions.left) {
  newX = Math.max(newX - GRID_SIZE, 0);
}
if (actions.right) {
  newX = Math.min(newX + GRID_SIZE, SCREEN_WIDTH - GRID_SIZE);
}

state.frogX = newX;
state.frogY = newY;

// Update frog sprite position
frog.position = { x: state.frogX, y: state.frogY };

// Determine if frog is in water
state.inWater = WATER_LANES.some(y => Math.abs(state.frogY - y) < 25);

// Simplified collision detection for cars
// In a full implementation, you'd compare actual bounding boxes
let hitByCar = false;
for (let i = 0; i < CAR_LANES.length; i++) {
  if (Math.abs(state.frogY - CAR_LANES[i]) < CAR_COLLISION_THRESHOLD) {
    // Check if frog overlaps with any car in this lane
    hitByCar = true;
    break;
  }
}

if (hitByCar) {
  // Respawn on car collision
  state.frogX = START_X;
  state.frogY = START_Y;
  state.inWater = false;
  state.onLog = false;
}

// Check if in water without being on a log = drown
if (state.inWater && !state.onLog) {
  // Respawn on drowning
  state.frogX = START_X;
  state.frogY = START_Y;
  state.inWater = false;
}

// Check for goal (reached top)
if (state.frogY <= GOAL_Y) {
  // Level complete! Can reset for next round
  state.frogX = START_X;
  state.frogY = START_Y;
  state.inWater = false;
  state.onLog = false;
}

// Keep frog in bounds
state.frogX = Math.max(0, Math.min(state.frogX, SCREEN_WIDTH - GRID_SIZE));
state.frogY = Math.max(0, Math.min(state.frogY, SCREEN_HEIGHT - GRID_SIZE));

// Output current game state
output.data_out = {
  frogX: state.frogX,
  frogY: state.frogY,
  inWater: state.inWater,
  onLog: state.onLog,
  gameActive: state.gameActive,
  carLanes: CAR_LANES,
  waterLanes: WATER_LANES
};

